    # @guarantee('Evaluate objects that are not evaluated by default like limits,')
    # Proof: LibraryAxiom('Adjoint.doit_contract')
    def doit(self, **hints):
        arg = self.arg
        if hints.get('deep', True) and isinstance(arg, Basic):
            return adjoint(arg.doit(**hints))
        else:
            return adjoint(self.arg)

    @property
    # ── CCTT: Adjoint.arg [no proof generated] ──
    def arg(self):
        return self.args[0]

    @property
    # ── CCTT: Adjoint.shape [no proof generated] ──
    def shape(self):
        return self.arg.shape[::-1]

    def _entry(self, i, j, **kwargs):
        return conjugate(self.arg._entry(j, i, **kwargs))

    def _eval_adjoint(self):
        return self.arg

    def _eval_transpose(self):
        return self.arg.conjugate()

    def _eval_conjugate(self):
        return self.arg.transpose()

    def _eval_trace(self):
        from sympy.matrices.expressions.trace import Trace
        return conjugate(Trace(self.arg))



